package com.example.smartwastemanagementapp.ui.screens
import androidx.compose.animation.core.* import androidx.compose.foundation.Image import androidx.compose.foundation.background import androidx.compose.foundation.layout.* import androidx.compose.material3.MaterialTheme import androidx.compose.material3.Text import androidx.compose.runtime.* import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.draw.alpha import androidx.compose.ui.res.painterResource import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import com.example.smartwastemanagementapp.R import kotlinx.coroutines.delay
@Composable fun SplashScreen(onTimeout: () -> Unit) { // Always use the latest callback — avoids stale-closure crash val currentOnTimeout by rememberUpdatedState(onTimeout)
LaunchedEffect(Unit) { delay(2000) currentOnTimeout() }
// Fade-in animation for logo val alpha by animateFloatAsState( targetValue = 1f, animationSpec = tween(durationMillis = 900, easing = FastOutSlowInEasing), label = "splash_alpha" )
Box( modifier = Modifier .fillMaxSize() .background(MaterialTheme.colorScheme.background), contentAlignment = Alignment.Center ) { Column( horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center, modifier = Modifier.alpha(alpha) ) { Image( painter = painterResource(id = R.drawable.app_logo), contentDescription = "App Logo", modifier = Modifier.size(140.dp) ) Spacer(modifier = Modifier.height(24.dp)) Text( text = "CivicFix", style = MaterialTheme.typography.headlineLarge.copy( fontWeight = FontWeight.Bold, fontSize = 32.sp ), color = MaterialTheme.colorScheme.primary ) Text( text = "Manage Waste Smartly", style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant ) } } }

